     1→use askama::Template;
     2→use axum::extract::{Path, State};
     3→use axum::http::StatusCode;
     4→use axum::response::{Html, IntoResponse, Redirect, Response};
     5→use axum::Form;
     6→use sqlx::PgPool;
     7→use uuid::Uuid;
     8→
     9→use super::auth::AuthenticatedUser;
    10→use crate::domain::{TodoItem, TodoItemId};
    11→use crate::services::todo_service::{
    12→    add_todo, delete_todo, get_todos, toggle_todo_completion, update_todo_title, AddTodoError,
    13→    DeleteTodoError, ToggleTodoError, UpdateTitleError,
    14→};
    15→
    16→/// View model for a single todo item in the template.
    17→pub struct TodoItemView {
    18→    pub id: String,
    19→    pub title: String,
    20→    pub is_completed: bool,
    21→}
    22→
    23→impl From<&TodoItem> for TodoItemView {
    24→    fn from(item: &TodoItem) -> Self {
    25→        Self {
    26→            id: item.id().as_uuid().to_string(),
    27→            title: item.title().as_str().to_string(),
    28→            is_completed: item.is_completed(),
    29→        }
    30→    }
    31→}
    32→
    33→#[derive(Template)]
    34→#[template(path = "todos.html")]
    35→pub struct TodosTemplate {
    36→    pub todos: Vec<TodoItemView>,
    37→    pub error_message: Option<String>,
    38→}
    39→
    40→pub async fn get_todos_page(
    41→    AuthenticatedUser(user_id): AuthenticatedUser,
    42→    State(pool): State<PgPool>,
    43→) -> Result<impl IntoResponse, TodosError> {
    44→    let todos = get_todos(&pool, &user_id)
    45→        .await
    46→        .map_err(TodosError::Unexpected)?;
    47→
    48→    let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();
    49→
    50→    let template = TodosTemplate {
    51→        todos: todo_views,
    52→        error_message: None,
    53→    };
    54→    Ok(Html(template.render()?))
    55→}
    56→
    57→#[derive(serde::Deserialize)]
    58→pub struct AddTodoForm {
    59→    pub title: String,
    60→}
    61→
    62→pub async fn post_todo(
    63→    AuthenticatedUser(user_id): AuthenticatedUser,
    64→    State(pool): State<PgPool>,
    65→    Form(form): Form<AddTodoForm>,
    66→) -> Result<Response, TodosError> {
    67→    // Silently ignore empty/whitespace-only submissions per US-5
    68→    if form.title.trim().is_empty() {
    69→        return Ok(Redirect::to("/todos").into_response());
    70→    }
    71→
    72→    match add_todo(&pool, user_id.clone(), form.title).await {
    73→        Ok(_) => Ok(Redirect::to("/todos").into_response()),
    74→        Err(AddTodoError::InvalidTitle(title_err)) => {
    75→            let user_facing = match title_err {
    76→                crate::domain::TodoTitleError::Empty => {
    77→                    // Should not reach here due to empty check above, but handle gracefully
    78→                    return Ok(Redirect::to("/todos").into_response());
    79→                }
    80→                crate::domain::TodoTitleError::TooLong { max, .. } => {
    81→                    format!("That title is too long (max {max} characters)")
    82→                }
    83→            };
    84→
    85→            let todos = get_todos(&pool, &user_id)
    86→                .await
    87→                .map_err(TodosError::Unexpected)?;
    88→            let todo_views: Vec<TodoItemView> = todos.iter().map(TodoItemView::from).collect();
    89→
    90→            let template = TodosTemplate {
    91→                todos: todo_views,
    92→                error_message: Some(user_facing),
    93→            };
    94→            let body = template.render().map_err(TodosError::Render)?;
    95→            Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
    96→        }
    97→        Err(AddTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
    98→    }
    99→}
   100→
   101→pub async fn post_toggle_todo(
   102→    AuthenticatedUser(user_id): AuthenticatedUser,
   103→    State(pool): State<PgPool>,
   104→    Path(todo_id): Path<Uuid>,
   105→) -> Result<Response, TodosError> {
   106→    let todo_item_id = TodoItemId::from_uuid(todo_id);
   107→
   108→    match toggle_todo_completion(&pool, &todo_item_id, &user_id).await {
   109→        Ok(_) => Ok(Redirect::to("/todos").into_response()),
   110→        Err(ToggleTodoError::NotFound) => Ok((
   111→            StatusCode::NOT_FOUND,
   112→            Html("<h1>Todo not found</h1>".to_string()),
   113→        )
   114→            .into_response()),
   115→        Err(ToggleTodoError::Unauthorized) => Ok((
   116→            StatusCode::FORBIDDEN,
   117→            Html("<h1>Not authorized</h1>".to_string()),
   118→        )
   119→            .into_response()),
   120→        Err(ToggleTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
   121→    }
   122→}
   123→
   124→pub async fn post_delete_todo(
   125→    AuthenticatedUser(user_id): AuthenticatedUser,
   126→    State(pool): State<PgPool>,
   127→    Path(todo_id): Path<Uuid>,
   128→) -> Result<Response, TodosError> {
   129→    let todo_item_id = TodoItemId::from_uuid(todo_id);
   130→
   131→    match delete_todo(&pool, &todo_item_id, &user_id).await {
   132→        Ok(()) => Ok(Redirect::to("/todos").into_response()),
   133→        Err(DeleteTodoError::NotFound) => Ok((
   134→            StatusCode::NOT_FOUND,
   135→            Html("<h1>Todo not found</h1>".to_string()),
   136→        )
   137→            .into_response()),
   138→        Err(DeleteTodoError::Unauthorized) => Ok((
   139→            StatusCode::FORBIDDEN,
   140→            Html("<h1>Not authorized</h1>".to_string()),
   141→        )
   142→            .into_response()),
   143→        Err(DeleteTodoError::Unexpected(err)) => Err(TodosError::Unexpected(err)),
   144→    }
   145→}
   146→
   147→#[derive(Template)]
   148→#[template(path = "edit_todo.html")]
   149→pub struct EditTodoTemplate {
   150→    pub todo_id: String,
   151→    pub current_title: String,
   152→    pub error_message: Option<String>,
   153→}
   154→
   155→pub async fn get_edit_todo(
   156→    AuthenticatedUser(user_id): AuthenticatedUser,
   157→    State(pool): State<PgPool>,
   158→    Path(todo_id): Path<Uuid>,
   159→) -> Result<Response, TodosError> {
   160→    let todo_item_id = TodoItemId::from_uuid(todo_id);
   161→
   162→    let item = crate::infrastructure::todo_repository::find_todo_by_id(&pool, &todo_item_id)
   163→        .await
   164→        .map_err(|e| TodosError::Unexpected(anyhow::anyhow!("Database error: {e}")))?;
   165→
   166→    match item {
   167→        Some(todo) if todo.user_id() == &user_id => {
   168→            let template = EditTodoTemplate {
   169→                todo_id: todo_id.to_string(),
   170→                current_title: todo.title().as_str().to_string(),
   171→                error_message: None,
   172→            };
   173→            Ok(Html(template.render()?).into_response())
   174→        }
   175→        Some(_) => Ok((
   176→            StatusCode::FORBIDDEN,
   177→            Html("<h1>Not authorized</h1>".to_string()),
   178→        )
   179→            .into_response()),
   180→        None => Ok((
   181→            StatusCode::NOT_FOUND,
   182→            Html("<h1>Todo not found</h1>".to_string()),
   183→        )
   184→            .into_response()),
   185→    }
   186→}
   187→
   188→#[derive(serde::Deserialize)]
   189→pub struct EditTodoForm {
   190→    pub title: String,
   191→}
   192→
   193→pub async fn post_edit_todo(
   194→    AuthenticatedUser(user_id): AuthenticatedUser,
   195→    State(pool): State<PgPool>,
   196→    Path(todo_id): Path<Uuid>,
   197→    Form(form): Form<EditTodoForm>,
   198→) -> Result<Response, TodosError> {
   199→    let todo_item_id = TodoItemId::from_uuid(todo_id);
   200→
   201→    match update_todo_title(&pool, &todo_item_id, &user_id, form.title.clone()).await {
   202→        Ok(()) => Ok(Redirect::to("/todos").into_response()),
