// --- HTMX progressive enhancement tests ---

#[tokio::test]
async fn base_html_includes_htmx_script() {
    let app = spawn_app().await;
    let client = register_and_login(&app.address, "htmx@example.com", "securepassword123").await;

    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    let body = response.text().await.unwrap();
    assert!(
        body.contains("htmx.min.js"),
        "Base template should include the HTMX script"
    );
}

#[tokio::test]
async fn get_todos_with_hx_request_returns_fragment() {
    let app = spawn_app().await;
    let client = register_and_login(&app.address, "htmxfrag@example.com", "securepassword123").await;

    // Add a todo first so we have content
    client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "HTMX test item")])
        .send()
        .await
        .expect("Failed to add todo");

    // Request with HX-Request header (simulating HTMX)
    let response = client
        .get(format!("{}/todos", &app.address))
        .header("HX-Request", "true")
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);
    let body = response.text().await.unwrap();

    // Should NOT contain full page elements
    assert!(
        !body.contains("<!DOCTYPE html>"),
        "HTMX fragment should not contain DOCTYPE"
    );
    assert!(
        !body.contains("<html"),
        "HTMX fragment should not contain <html> tag"
    );

    // Should contain the todo content
    assert!(
        body.contains("HTMX test item"),
        "HTMX fragment should contain the todo item"
    );
}

